class Solution {
public:
    vector<int> validSequence(string word1, string word2) {
        vector<int> res;
        for (int i = 0; i < word1.size(); i++) {
            if (word1[i] != word2[0]) {
                res.push_back(i);
                word2 = word2.substr(1);
                if (word2.empty()) return res;
            } else {
                word2 = word2.substr(1);
            }
        }
        return {};
    }
};
